const getTipsText = (isThisWeek: boolean, date: string) => {
  if (date) {
    if (isThisWeek) {
      return "*任务根据宝贝本周的薄弱点智能定制生成";
    } else if (dayjs().isAfter(dayjs(date).endOf("week"))) {
      return "*根据当周宝贝的薄弱点，智能生成查漏补缺任务";
    } else {
      return "*根据本周宝贝的薄弱点，智能生成下周查漏补缺任务";
    }
  } else {
    if (isThisWeek) {
      return "*任务根据宝贝本周的薄弱点智能定制生成";
    } else if (dayjs().day() === 0) {
      return "*根据本周宝贝的薄弱点，智能生成下周查漏补缺任务";
    } else {
      return "*根据当周宝贝的薄弱点，智能生成查漏补缺任务";
    }
  }
};
const getActionText = (isThisWeek: boolean, date: string) => {
  if (date) {
    if (isThisWeek) {
      return "周末";
    } else if (dayjs().isAfter(dayjs(date).endOf("week"))) {
      return "本周";
    } else {
      return "下周";
    }
  } else {
    if (isThisWeek) {
      return "周末";
    } else if (dayjs().day() === 0) {
      return "下周";
    } else {
      return "本周";
    }
  }
};

const hourAndMin = computed(() => {
  const totalMin = getTotalMin(choosedTaskArr.value);
  return getHourAndMin(totalMin);
});
const getTaskTime = (min: number) => {
  const { h, m } = getHourAndMin(min);
  return getDisplayTime(h, m);
};
const formatTaskDate = (startTime: number, endTime: number) => {
  // 日期格式为10位

  if (dayjs.unix(startTime).isSame(dayjs.unix(endTime), "day")) {
    return dayjs.unix(startTime).format("M月D日 [周]dd");
  }
  return (
    dayjs.unix(startTime).format("M月D日 [周]dd") +
    "-" +
    dayjs.unix(endTime).format("M月D日 [周]dd")
  );
};

const onLoad = async () => {
  page.value++;

  const data: {
    page: number;
    page_size: number;
    type: number;
    date: LocationQueryValue | LocationQueryValue[];
    interact_id: LocationQueryValue | LocationQueryValue[];
