  } = {
    page: page.value,
    page_size: PAGESIZE,
    type: Number(type),
    date,
    interact_id,
  };
  if (tal_id) {
    data.stu_tal_id = tal_id;
  }
  const res = await taskAssistantDetail(data);
  if (res.data.errcode !== 0) {
    // 状态码不正确，提前结束
    loading.value = false;
    finished.value = true;
    return;
  }

  const addList = res.data.data.task_list ?? [];
  list.value = [...list.value, ...addList];
  setLoadedTaskListCount(list.value.length)
  isFetched.value = true;

  if (page.value === 1) {
    title.value = res.data.data.title;
  }

  // 进入任务助手页面，需要通过接口设置选中的任务列表。
