export const taskAssistantDetail = async (data: any) => {

  const { stu_talid, token } = await getUserInfo();
  return ApiService.post("/stu-parent/schedule/v1/task-assistant/detail", {
    stu_tal_id: stu_talid,
    ...data,
    token,
  });

};



